from pathlib import Path
import re
import sys

project = Path(sys.argv[1]).resolve() if len(sys.argv) > 1 else Path.cwd().resolve()
path = project / "apps/api/app/services/pipeline.py"
if not path.exists():
    raise SystemExit("Run from the edgeboard-v3 repository root.")
source = path.read_text(encoding="utf-8")
source = source.replace("from datetime import date, datetime, timezone", "from datetime import date, datetime, timezone\nfrom time import perf_counter")
source = source.replace("from sqlalchemy import delete, select", "from sqlalchemy import delete, select\nfrom sqlalchemy.exc import IntegrityError")

def replace_async_method(source, name, next_name, replacement):
    pattern = re.compile(rf"    async def {name}\(self\) -> dict:\n.*?(?=    (?:async )?def {next_name}\()", re.S)
    if not pattern.search(source):
        raise SystemExit(f"Could not find {name}()")
    return pattern.sub(lambda _: replacement, source)

source = replace_async_method(source, "refresh_mlb", "refresh_odds", '    async def refresh_mlb(self) -> dict:\n        run_id = self._start_run("mlb")\n        started = perf_counter()\n        try:\n            season = date.today().year\n            schedule, standings = await self.mlb.schedule(), await self.mlb.standings(season)\n            pitcher_ids: dict[int, str] = {}\n\n            with SessionLocal() as db:\n                existing_games = {\n                    game.external_id: game\n                    for game in db.scalars(select(Game).where(Game.external_id.like("mlb-%"))).all()\n                }\n                seen_external_ids: set[str] = set()\n                inserted = 0\n                updated = 0\n\n                for payload in schedule:\n                    teams = payload.get("teams", {})\n                    home = teams.get("home", {}).get("team", {})\n                    away = teams.get("away", {}).get("team", {})\n                    venue = payload.get("venue", {})\n                    game_pk = payload.get("gamePk")\n                    if not game_pk:\n                        continue\n                    external_id = f"mlb-{game_pk}"\n                    if external_id in seen_external_ids:\n                        continue\n                    seen_external_ids.add(external_id)\n\n                    game = existing_games.get(external_id)\n                    if game is None:\n                        game = Game(external_id=external_id)\n                        existing_games[external_id] = game\n                        db.add(game)\n                        inserted += 1\n                    else:\n                        updated += 1\n\n                    game.mlb_game_pk = game_pk\n                    game.home_team = home.get("name", "")\n                    game.away_team = away.get("name", "")\n                    game.home_team_id = home.get("id")\n                    game.away_team_id = away.get("id")\n                    game.venue_name = venue.get("name", "")\n                    game.venue_id = venue.get("id")\n                    game.starts_at = parse_dt(payload.get("gameDate")) or datetime.now(timezone.utc)\n                    game.status = payload.get("status", {}).get("detailedState", "scheduled")\n                    home_pitcher = teams.get("home", {}).get("probablePitcher", {})\n                    away_pitcher = teams.get("away", {}).get("probablePitcher", {})\n                    game.home_probable_pitcher_id = home_pitcher.get("id")\n                    game.home_probable_pitcher = home_pitcher.get("fullName", "")\n                    game.away_probable_pitcher_id = away_pitcher.get("id")\n                    game.away_probable_pitcher = away_pitcher.get("fullName", "")\n                    if game.home_probable_pitcher_id:\n                        pitcher_ids[game.home_probable_pitcher_id] = game.home_probable_pitcher\n                    if game.away_probable_pitcher_id:\n                        pitcher_ids[game.away_probable_pitcher_id] = game.away_probable_pitcher\n                    game.home_score = teams.get("home", {}).get("score")\n                    game.away_score = teams.get("away", {}).get("score")\n                    game.source_updated_at = datetime.now(timezone.utc)\n\n                captured = date.today().isoformat()\n                existing_teams = {\n                    snap.team_id: snap\n                    for snap in db.scalars(select(TeamSnapshot).where(\n                        TeamSnapshot.season == season,\n                        TeamSnapshot.captured_date == captured,\n                    )).all()\n                }\n                for record in standings:\n                    team = record.get("team", {})\n                    team_id = team.get("id")\n                    if not team_id:\n                        continue\n                    games_played = max(int(record.get("gamesPlayed", 0) or 0), 1)\n                    runs_scored = int(record.get("runsScored", 0) or 0)\n                    runs_allowed = int(record.get("runsAllowed", 0) or 0)\n                    snap = existing_teams.get(team_id)\n                    if snap is None:\n                        snap = TeamSnapshot(team_id=team_id, season=season, captured_date=captured)\n                        existing_teams[team_id] = snap\n                        db.add(snap)\n                    snap.team_name = team.get("name", "")\n                    snap.wins = int(record.get("wins", 0) or 0)\n                    snap.losses = int(record.get("losses", 0) or 0)\n                    snap.runs_per_game = runs_scored / games_played\n                    snap.runs_allowed_per_game = runs_allowed / games_played\n                    snap.run_differential_per_game = (runs_scored - runs_allowed) / games_played\n                    snap.raw = record\n                db.commit()\n\n            pitcher_count = 0\n            for pitcher_id, name in pitcher_ids.items():\n                stats = await self.mlb.pitcher_stats(pitcher_id, season)\n                if not stats:\n                    continue\n                with SessionLocal() as db:\n                    captured = date.today().isoformat()\n                    snap = db.scalar(select(PitcherSnapshot).where(\n                        PitcherSnapshot.pitcher_id == pitcher_id,\n                        PitcherSnapshot.season == season,\n                        PitcherSnapshot.captured_date == captured,\n                    ))\n                    if snap is None:\n                        snap = PitcherSnapshot(\n                            pitcher_id=pitcher_id,\n                            season=season,\n                            captured_date=captured,\n                        )\n                        db.add(snap)\n                    snap.pitcher_name = name\n                    snap.era = to_float(stats.get("era"))\n                    snap.whip = to_float(stats.get("whip"))\n                    snap.strikeouts_per_9 = to_float(stats.get("strikeoutsPer9Inn"))\n                    snap.walks_per_9 = to_float(stats.get("walksPer9Inn"))\n                    snap.innings_pitched = to_float(stats.get("inningsPitched"))\n                    snap.raw = stats\n                    db.commit()\n                    pitcher_count += 1\n\n            details = {\n                "games_received": len(schedule),\n                "unique_games": len(seen_external_ids),\n                "games_inserted": inserted,\n                "games_updated": updated,\n                "teams": len(standings),\n                "pitchers": pitcher_count,\n                "duration_ms": round((perf_counter() - started) * 1000),\n            }\n            self._finish_run(run_id, "success", details)\n            return details\n        except Exception as exc:\n            category, friendly = self._classify_error(exc)\n            self._finish_run(\n                run_id,\n                "failed",\n                {"category": category, "duration_ms": round((perf_counter() - started) * 1000)},\n                friendly,\n            )\n            raise\n\n')
source = replace_async_method(source, "refresh_odds", "refresh_weather", '    async def refresh_odds(self) -> dict:\n        run_id = self._start_run("odds")\n        started = perf_counter()\n        try:\n            events, usage = await self.odds.fetch_mlb_odds()\n            rows = self.odds.normalize(events)\n            with SessionLocal() as db:\n                event_ids = [event["id"] for event in events]\n                existing_games = {\n                    game.external_id: game\n                    for game in db.scalars(select(Game).where(Game.external_id.in_(event_ids))).all()\n                } if event_ids else {}\n\n                inserted = 0\n                updated = 0\n                for event in events:\n                    game = existing_games.get(event["id"])\n                    if game is None:\n                        game = Game(external_id=event["id"])\n                        existing_games[event["id"]] = game\n                        db.add(game)\n                        inserted += 1\n                    else:\n                        updated += 1\n                    game.home_team = event["home_team"]\n                    game.away_team = event["away_team"]\n                    game.starts_at = parse_dt(event["commence_time"]) or datetime.now(timezone.utc)\n                    game.status = "scheduled"\n                    game.venue_name = STADIUMS.get(game.home_team, {}).get("venue", "")\n\n                existing_keys = set()\n                latest_capture = max((row["captured_at"] for row in rows), default=None)\n                if latest_capture:\n                    existing_keys = {\n                        (item.game_external_id, item.bookmaker, item.market, item.selection, item.line, item.captured_at)\n                        for item in db.scalars(select(OddsSnapshot).where(\n                            OddsSnapshot.captured_at == latest_capture\n                        )).all()\n                    }\n\n                saved_outcomes = 0\n                skipped_duplicates = 0\n                for row in rows:\n                    key = (\n                        row["game_external_id"], row["bookmaker"], row["market"],\n                        row["selection"], row["line"], row["captured_at"],\n                    )\n                    if key in existing_keys:\n                        skipped_duplicates += 1\n                        continue\n                    existing_keys.add(key)\n                    db.add(OddsSnapshot(\n                        game_external_id=row["game_external_id"],\n                        bookmaker=row["bookmaker"],\n                        market=row["market"],\n                        selection=row["selection"],\n                        american_odds=row["american_odds"],\n                        line=row["line"],\n                        bookmaker_updated_at=parse_dt(row["bookmaker_updated_at"]),\n                        captured_at=row["captured_at"],\n                    ))\n                    saved_outcomes += 1\n                db.commit()\n\n            details = {\n                "events": len(events),\n                "games_inserted": inserted,\n                "games_updated": updated,\n                "outcomes_saved": saved_outcomes,\n                "duplicates_skipped": skipped_duplicates,\n                "quota": usage,\n                "duration_ms": round((perf_counter() - started) * 1000),\n            }\n            self._finish_run(run_id, "success", details)\n            return details\n        except Exception as exc:\n            category, friendly = self._classify_error(exc)\n            self._finish_run(\n                run_id,\n                "failed",\n                {"category": category, "duration_ms": round((perf_counter() - started) * 1000)},\n                friendly,\n            )\n            raise\n\n')
marker = "    def _start_run(self, job_name: str) -> int:"
if "_classify_error" not in source:
    source = source.replace(marker, '    @staticmethod\n    def _classify_error(exc: Exception) -> tuple[str, str]:\n        message = str(exc).lower()\n        if isinstance(exc, IntegrityError) or "unique constraint" in message or "duplicate key" in message:\n            return ("database_conflict", "A duplicate database record was detected. The transaction was rolled back safely.")\n        if "timeout" in message:\n            return ("provider_timeout", "A data provider timed out. EdgeBoard will retry automatically.")\n        if "401" in message or "403" in message or "api key" in message:\n            return ("authentication", "A provider credential was rejected. Check Render environment variables.")\n        if "429" in message or "quota" in message or "rate limit" in message:\n            return ("rate_limit", "A provider usage limit was reached. The next scheduled refresh will try again.")\n        if "connection" in message or "network" in message:\n            return ("network", "A provider connection failed. EdgeBoard will retry automatically.")\n        return ("unknown", "The refresh failed unexpectedly. Technical details remain in the server logs.")\n\n' + marker)
path.write_text(source, encoding="utf-8")
print("Pipeline stability patch installed.")
